import json
import sys

def calculate_bias_metrics(data_json: str) -> str:
    data = json.loads(data_json)
    predictions = data["predictions"]
    thresholds = data["thresholds"]

    groups = {}
    for p in predictions:
        g = p["group"]
        if g not in groups:
            groups[g] = []
        groups[g].append(p)

    group_stats = {}
    for g, preds in groups.items():
        total = len(preds)
        positives = sum(1 for p in preds if p["predicted"] == 1)
        positive_rate = round(positives / total, 2)

        actual_pos = [p for p in preds if p["actual"] == 1]
        actual_neg = [p for p in preds if p["actual"] == 0]

        tpr = round(sum(1 for p in actual_pos if p["predicted"] == 1) / len(actual_pos), 2) if actual_pos else 0.0
        fpr = round(sum(1 for p in actual_neg if p["predicted"] == 1) / len(actual_neg), 2) if actual_neg else 0.0

        group_stats[g] = {"total": total, "positive_rate": positive_rate, "tpr": tpr, "fpr": fpr}

    group_keys = sorted(groups.keys())
    g_a = group_stats[group_keys[0]]
    g_b = group_stats[group_keys[1]]

    dpd = round(abs(g_a["positive_rate"] - g_b["positive_rate"]), 2)
    eod = round(max(abs(g_a["tpr"] - g_b["tpr"]), abs(g_a["fpr"] - g_b["fpr"])), 2)

    if max(g_a["positive_rate"], g_b["positive_rate"]) > 0:
        dir_val = round(min(g_a["positive_rate"], g_b["positive_rate"]) / max(g_a["positive_rate"], g_b["positive_rate"]), 2)
    else:
        dir_val = 1.0

    fairness_flags = [
        {"metric": "demographic_parity_difference", "value": dpd, "threshold": thresholds["demographic_parity_max"], "status": "PASS" if dpd <= thresholds["demographic_parity_max"] else "FAIL"},
        {"metric": "equalized_odds_difference", "value": eod, "threshold": thresholds["equalized_odds_max"], "status": "PASS" if eod <= thresholds["equalized_odds_max"] else "FAIL"},
        {"metric": "disparate_impact_ratio", "value": dir_val, "threshold": thresholds["disparate_impact_min"], "status": "PASS" if dir_val >= thresholds["disparate_impact_min"] else "FAIL"}
    ]

    overall = "PASS" if all(f["status"] == "PASS" for f in fairness_flags) else "FAIL"

    result = {
        "group_stats": group_stats,
        "metrics": {
            "demographic_parity_difference": dpd,
            "equalized_odds_difference": eod,
            "disparate_impact_ratio": dir_val
        },
        "fairness_flags": fairness_flags,
        "overall_fairness": overall
    }
    return json.dumps(result)

result = calculate_bias_metrics(sys.stdin.read())
print(result)
